sql:
SELECT COUNT(DISTINCT athlete_id) 
FROM performances 
WHERE event_id = (SELECT MAX(event_id) FROM performances);

SELECT name 
FROM athletes 
WHERE athlete_id = 0;

external_knowledge:
- 'sailing under the banner of perfect health' refers to athletes with medical conditions (which could be empty or indicate no severe conditions);
- 'training voyages' metaphorically refers to training sessions;
- 'competitions they participated in' refers to the competition names and events they took part in;
- 'peak performance on the clear waters of metric 1' refers to their best performance on metric_id 1;
- 'safe harbor contacts' metaphorically refers to emergency contacts, indicating a place of safety or support.

- 'short dash' refers to the 100m Sprint; 
- 'identities' refer to the athletes' names; 
- 'localities' refer to the athletes' districts; 
- 'peak times' refer to their best recorded performances in the event.

sql:
SELECT athletes.name, COALESCE(districts.district_name, 'unknown') AS district_name
FROM athletes
LEFT JOIN districts ON athletes.district_id = districts.district_id;

SELECT athlete_id, name  
FROM athletes
WHERE athlete_id NOT IN (SELECT DISTINCT athlete_id FROM performances);

external_knowledge:
- "health notes" refers to "medical_conditions";
- "mentors" refers to "coaches";
- "most recent date" refers to the maximum session date for each athlete;
- Consider "workout session" as a synonym for "training session".

sql:
SELECT athletes.name
FROM athletes
ORDER BY athletes.name ASC;

SELECT athletes.name, performances.performance_time 
FROM athletes 
JOIN performances ON athletes.athlete_id = performances.athlete_id;
